/**
 * Refresh a DOM tree recursively
 */
function refreshTree(root) {
  if (root.refresh) {
    root.refresh();
    return;
  }
  for (let i = 0; i < root.children.length; i++) {
    refreshTree(root.children[i]);
  }
}

