function makeSelectForCategory(dom, kb, subject, category, dataDoc, callbackFunction) {
  const du = kb.any(category, ns.owl('disjointUnionOf'));
  let subs;
  let multiple = false;
  if (!du) {
    subs = kb.each(undefined, ns.rdfs('subClassOf'), category);
    multiple = true;
  } else {
    subs = du.elements;
  }
  debug('Select list length ' + subs.length);
  if (subs.length === 0) {
    return errorMessageBlock(dom, 'Can\'t do ' + (multiple ? 'multiple ' : '') + 'selector with no subclasses of category: ' + category);
  }
  if (subs.length === 1) {
    return errorMessageBlock(dom, 'Can\'t do ' + (multiple ? 'multiple ' : '') + 'selector with only 1 subclass of category: ' + category + ':' + subs[1]);
  }
  return makeSelectForClassifierOptions(dom, kb, subject, ns.rdf('type'), subs, {
    multiple,
    nullLabel: '* Select type *'
  }, dataDoc, callbackFunction);
}

