const value = [];
function get(k) {
  return value[k];
}
function set(k, v) {
  if (typeof v !== 'string') {
    src_debug/* log */.Rm('Non-string value of preference ' + k + ': ' + v);
    throw new Error('Non-string value of preference ' + k + ': ' + v);
  }
  this.value[k] = v;
}

// In a solid world, Preferences are stored in the web
//
// Make an RDF node for recording the common view preferences for any object
// (maybe make it in a separate file?)
function recordSharedPreferences(subject, context) {
  return new Promise(function (resolve, reject) {
    const sharedPreferences = preferences_kb.any(subject, ns.ui('sharedPreferences'));
    if (!sharedPreferences) {
      if (!preferences_kb.updater.editable(subject.doc())) {
        src_debug/* log */.Rm(` Cant make shared preferences, may not change ${subject.doc}`);
        resolve(context);
      }
      const sp = external_$rdf_.sym(subject.doc().uri + '#SharedPreferences');
      const ins = [external_$rdf_.st(subject, ns.ui('sharedPreferences'), sp, subject.doc())];
      src_debug/* log */.Rm('Creating shared preferences ' + sp);
      preferences_kb.updater.update([], ins, function (uri, ok, errorMessage) {
        if (!ok) {
          reject(new Error('Error creating shared prefs: ' + errorMessage));
        } else {
          context.sharedPreferences = sp;
          resolve(context);
        }
      });
    } else {
      context.sharedPreferences = sharedPreferences;
      resolve(context);
    }
  });
}

// Construct a personal defaults node in the preferences file for a given class of object
//
function recordPersonalDefaults(theClass, context) {
  return new Promise(function (resolve, reject) {
    ensureLoadedPreferences(context).then(context => {
      if (!context.preferencesFile) {
        src_debug/* log */.Rm('Not doing private class preferences as no access to preferences file. ' + context.preferencesFileError);
        return;
      }
      const regs = preferences_kb.each(null, ns.solid('forClass'), theClass, context.preferencesFile);
      let ins = [];
      let prefs;
      let reg;
      if (regs.length) {
        // Use existing node if we can
        regs.forEach(r => {
          prefs = prefs || preferences_kb.any(r, ns.solid('personalDefaults'));
        });
        if (prefs) {
          context.personalDefaults = prefs; // Found one
          resolve(context);
          return;
        } else {
          prefs = newThing(context.preferencesFile);
          reg = regs[0];
        }
      } else {
        // no regs fo class
        reg = newThing(context.preferencesFile);
        ins = [external_$rdf_.st(reg, ns.rdf('type'), ns.solid('TypeRegistration'), context.preferencesFile), external_$rdf_.st(reg, ns.solid('forClass'), theClass, context.preferencesFile)];
      }
      prefs = newThing(context.preferencesFile);
      ins.push(external_$rdf_.st(reg, ns.solid('personalDefaults'), prefs, context.preferencesFile));
      preferences_kb.updater.update([], ins, function (uri, ok, errm) {
        if (!ok) {
          reject(new Error('Setting preferences for ' + theClass + ': ' + errm));
        } else {
          context.personalDefaults = prefs;
          resolve(context);
        }
      });
    }, err => {
      reject(err);
    });
  });
}
function renderPreferencesForm(subject, theClass, preferencesForm, context) {
  const prefContainer = context.dom.createElement('div');
  participationObject(subject, subject.doc(), context.me).then(participation => {
    const dom = context.dom;
    function heading(text) {
      prefContainer.appendChild(dom.createElement('h5')).textContent = text;
    }
    heading('My view of this ' + context.noun);
    appendForm(dom, prefContainer, {}, participation, preferencesForm, subject.doc(), (ok, mes) => {
      if (!ok) complain(context, mes);
    });
    heading('Everyone\'s  view of this ' + context.noun);
    recordSharedPreferences(subject, context).then(context => {
      const sharedPreferences = context.sharedPreferences;
      appendForm(dom, prefContainer, {}, sharedPreferences, preferencesForm, subject.doc(), (ok, mes) => {
        if (!ok) complain(context, mes);
      });
      heading('My default view of any ' + context.noun);
      recordPersonalDefaults(theClass, context).then(context => {
        appendForm(dom, prefContainer, {}, context.personalDefaults, preferencesForm, context.preferencesFile, (ok, mes) => {
          if (!ok) complain(context, mes);
        });
      }, err => {
        complain(context, err);
      });
    });
  }, err => {
    // parp object fails
    prefContainer.appendChild(errorMessageBlock(context.dom, err));
  });
  return prefContainer;
}

// This should be part of rdflib.js ad part of the RDFJS Standard!!

function toJS(term) {
  if (!term.datatype) return term; // Objects remain objects
  if (term.datatype.equals(ns.xsd('boolean'))) {
    return term.value === '1';
  }
  if (term.datatype.equals(ns.xsd('dateTime')) || term.datatype.equals(ns.xsd('date'))) {
    return new Date(term.value);
  }
  if (term.datatype.equals(ns.xsd('integer')) || term.datatype.equals(ns.xsd('float')) || term.datatype.equals(ns.xsd('decimal'))) {
    return Number(term.value);
  }
  return term.value;
}

// This is the function which acuakly reads and combines the preferences
//
//  @@ make it much more tolerant of missing buts of prefernces
function getPreferencesForClass(subject, theClass, predicates, context) {
  return new Promise(function (resolve, reject) {
    recordSharedPreferences(subject, context).then(context => {
      const sharedPreferences = context.sharedPreferences;
      if (context.me) {
        participationObject(subject, subject.doc(), context.me).then(participation => {
          recordPersonalDefaults(theClass, context).then(context => {
            const results = [];
            const personalDefaults = context.personalDefaults;
            predicates.forEach(pred => {
              // Order of preference: My settings on object, Global settings on object, my settings on class
              const v1 = preferences_kb.any(participation, pred) || preferences_kb.any(sharedPreferences, pred) || preferences_kb.any(personalDefaults, pred);
              if (v1) {
                results[pred.uri] = toJS(v1);
              }
            });
            resolve(results);
          }, reject);
        }, reject);
      } else {
        // no user defined, just use common prefs
        const results = [];
        predicates.forEach(pred => {
          const v1 = preferences_kb.any(sharedPreferences, pred);
          if (v1) {
            results[pred.uri] = toJS(v1);
          }
        });
        resolve(results);
      }
    });
  });
}

